import { createMetadata } from "@vendor/seo/metadata";
import type { Metadata } from "next";
import dynamic from "next/dynamic";
import type { SearchParams } from "nuqs/server";
import { EmailForm } from "../_components/email-form";
import { ErrorBanner } from "../_components/error-banner";
import { OAuthButton } from "../_components/oauth-button";
import { SeparatorWithText } from "../_components/separator-with-text";
import { loadSignInSearchParams } from "../_lib/search-params";

const OTPIsland = dynamic(() =>
  import("../_components/otp-island").then((m) => m.OTPIsland)
);
const SessionActivator = dynamic(() =>
  import("../_components/session-activator").then((m) => m.SessionActivator)
);

export const metadata: Metadata = createMetadata({
  title: "Sign In - Lightfast Auth",
  description:
    "Sign in to your Lightfast account to access the AI agent platform. Secure authentication portal for developers.",
  openGraph: {
    title: "Sign In - Lightfast Auth",
    description:
      "Sign in to your Lightfast account to access the AI agent platform.",
    url: "https://lightfast.ai/sign-in",
  },
  twitter: {
    title: "Sign In - Lightfast Auth",
    description:
      "Sign in to your Lightfast account to access the AI agent platform.",
  },
  alternates: {
    canonical: "https://lightfast.ai/sign-in",
  },
  robots: {
    index: true,
    follow: false,
  },
});

interface PageProps {
  searchParams: Promise<SearchParams>;
}

export default async function SignInPage({ searchParams }: PageProps) {
  const {
    step,
    email,
    redirect_url: redirectUrl,
    error,
    token,
    errorCode,
  } = await loadSignInSearchParams(searchParams);

  const hasError = !!(error ?? errorCode);

  return (
    <div className="w-full space-y-8">
      {/* Header — only on email step */}
      {step === "email" && !hasError && (
        <div className="text-center">
          <h1 className="font-medium font-pp text-3xl text-foreground">
            Log in to Lightfast
          </h1>
        </div>
      )}

      <div className="space-y-4">
        {/* Error display */}
        {(error ?? errorCode) && (
          <ErrorBanner
            backUrl="/sign-in"
            errorCode={errorCode}
            message={error}
          />
        )}

        {/* Step: email — server component form + client OAuth island */}
        {!hasError && step === "email" && (
          <>
            <EmailForm action="sign-in" redirectUrl={redirectUrl} />
            <SeparatorWithText text="Or" />
            <OAuthButton mode="sign-in" redirectUrl={redirectUrl} />
          </>
        )}

        {/* Step: code — client island (irreducible: OTP + Clerk FAPI) */}
        {!hasError && step === "code" && email && (
          <OTPIsland email={email} mode="sign-in" redirectUrl={redirectUrl} />
        )}

        {/* Step: activate — thin client island for session creation */}
        {step === "activate" && token && <SessionActivator token={token} />}
      </div>
    </div>
  );
}

import * as DropdownMenu from "@radix-ui/react-dropdown-menu";
import { useTRPC } from "@repo/app-trpc/react";
import { useQuery } from "@tanstack/react-query";
import { LogOut, Settings, User } from "lucide-react";

export function UserMenu() {
  const trpc = useTRPC();
  const query = useQuery(trpc.account.get.queryOptions());

  const email = query.data?.primaryEmailAddress ?? "";

  return (
    <DropdownMenu.Root>
      <DropdownMenu.Trigger asChild>
        <button aria-label="Settings" className="item" type="button">
          <Settings className="item__icon" size={16} />
          <span className="item__label">Settings</span>
        </button>
      </DropdownMenu.Trigger>

      <DropdownMenu.Portal>
        <DropdownMenu.Content
          align="start"
          className="user-menu-content"
          side="top"
          sideOffset={6}
        >
          <DropdownMenu.Label className="user-menu-label">
            <User className="user-menu-icon" size={14} />
            <span className="user-menu-email">{email}</span>
          </DropdownMenu.Label>

          <DropdownMenu.Separator className="user-menu-separator" />

          <DropdownMenu.Item
            className="user-menu-item"
            onSelect={() => void window.lightfastBridge.openWindow("settings")}
          >
            <Settings className="user-menu-icon" size={14} />
            Settings
          </DropdownMenu.Item>

          <DropdownMenu.Separator className="user-menu-separator" />

          <DropdownMenu.Item
            className="user-menu-item user-menu-item--destructive"
            onSelect={() => void window.lightfastBridge.auth.signOut()}
          >
            <LogOut className="user-menu-icon" size={14} />
            Log out
          </DropdownMenu.Item>
        </DropdownMenu.Content>
      </DropdownMenu.Portal>
    </DropdownMenu.Root>
  );
}

