1	import {
2	  createNeonHttpClient,
3	  type NeonHttpDatabase,
4	} from "./drivers/neon-http";
5	import { createPostgresClient } from "./drivers/postgres";
6	import { env } from "./env";
7	import { withBatchPolyfill } from "./polyfills/batch";
8	
9	// Canonical DB surface. Both drivers must satisfy this type — neon-http
10	// does so natively; postgres-js + withBatchPolyfill is bridged by an
11	// `as unknown as AppDatabase` cast in the local branch below.
12	type AppDatabase = NeonHttpDatabase;
13	
14	/**
15	 * Create a new database client.
16	 *
17	 * Routing:
18	 *   - Local dev (DATABASE_HOST is localhost / 127.0.0.1 / ::1)
19	 *       → postgres-js over TCP against the dev-services Docker Postgres,
20	 *         wrapped with `withBatchPolyfill` so `.batch()` call sites work.
21	 *   - Everything else
22	 *       → neon-http against PlanetScale's HTTP SQL endpoint.
23	 */
24	export function createClient(): AppDatabase {
25	  const databaseUrl = resolveDatabaseUrl({
26	    ssl: !isLocalDatabaseHost(env.DATABASE_HOST),
27	  });
28	
29	  if (isLocalDatabaseHost(env.DATABASE_HOST)) {
30	    return withBatchPolyfill(
31	      createPostgresClient(databaseUrl)
32	    ) as unknown as AppDatabase;
33	  }
34	
35	  return createNeonHttpClient(databaseUrl);
36	}
37	
38	/**
39	 * Default database client instance.
40	 */
41	export const db = createClient();
42	
43	// URL construction lives here (not in drivers/) because both drivers
44	// take a connection URL and the build logic — including ssl=require for
45	// remote hosts — is shared. Using URL/URL avoids string-interpolation
46	// bugs with special characters in passwords.
47	function resolveDatabaseUrl({ ssl }: { ssl: boolean }) {
48	  const url = new URL("postgresql://localhost");
49	  url.hostname = env.DATABASE_HOST;
50	  url.port = env.DATABASE_PORT ? String(env.DATABASE_PORT) : "";
51	  url.username = env.DATABASE_USERNAME;
52	  url.password = env.DATABASE_PASSWORD;
53	  url.pathname = `/${env.DATABASE_NAME ?? "postgres"}`;
54	  if (ssl) {
55	    url.searchParams.set("sslmode", "require");
56	  }
57	  return url.toString();
58	}
59	
60	// Driver-routing predicate lives here (not in env.ts, not in drivers/)
61	// because picking a driver is the orchestrator's job. Drivers don't
62	// know what "local" means — they just connect to the URL they're given.
63	// Note: drizzle.config.ts intentionally duplicates this 3-line check
64	// because drizzle-kit runs at build time with its own sync config and
65	// shouldn't depend on the runtime client module.
66	function isLocalDatabaseHost(value: string) {
67	  const hostname = value.toLowerCase();
68	  return (
69	    hostname === "localhost" || hostname === "127.0.0.1" || hostname === "::1"
70	  );
71	}
